        // 清理旧图 + 旧定时器
        if(we._graphRotateTimer) { clearInterval(we._graphRotateTimer); we._graphRotateTimer = null; }
        if(we._graph3d) { try { we._graph3d._destructor && we._graph3d._destructor(); } catch(e){} we._graph3d = null; }
