        let existing = scoped.find(c => c.fusionCycleKey === cycleKey || c.sourceFusionKey === cycleKey);
        if (!existing) existing = scoped.find(c => (c.source === 'fusion_creative_pipeline' || c.fusionCreative) && (c.order || c.number) === chapterNum);
