        };
    },

    _buildGeminiRequest(id, messages, config, options) {
        const base = (config.baseUrl || 'https://generativelanguage.googleapis.com/v1beta').replace(//+$/, '');
        const system = messages.filter(m => m.role === 'system').map(m => m.content).join('

');
