4. 一致性风险要指出续写时最容易写崩的地方。`;
        let raw = '';
        await AI.generate(prompt, { apiType: 'parse', module: 'world_import_outline', max_tokens: 2600, temperature: 0.2 }, c => { raw += c; });
        const clean = raw.trim().replace(/^```(?:json)?\s*/i, '').replace(/```$/i, '').trim();
