	            const zone = this._detectNovelImportZone(line);
	            if(zone) {
	                const prevZone = currentZone;
	                const payload = this._extractNovelImportZonePayload(line, zone);
	                if((zone === 'outline' || zone === 'body') && prevZone !== zone) {
	                    flushChapter();
