		        const sampleText = [
		            bookBrief ? `【一句话开书】\n${bookBrief.slice(0, 1200)}` : '',
		            sampleChaps.map(c => `【${c.title}】\n【章内细纲】\n${(c.outline||'').slice(0, 2400)}\n\n【正文校验样本】\n${(c.content||'').slice(0, 1200)}`).join('\n\n---\n\n')
